`endif
) u_vcmain_pok (
/*O*/ .gen_pok_o ( vcmain_pok_int )
);

assign vcmain_pok = vcmain_pok_int && vcmain_supp_i && main_pwr_dly_o ;
assign vcmain_pok_h = vcmain_pok;   // Level Shifter
assign vcmain_pok_o = vcaon_pok_o && vcmain_pok;


