always_ff @( posedge clk_i, negedge rst_ni ) begin
  if ( !rst_ni ) begin
    rng_b_r <= {EntropyStreams{1'b0}};
    rng_b_o <= {EntropyStreams{1'b0}};
  end
  else begin
    rng_b_r <= rng_b;
    rng_b_o <= rng_b_r;
  end
end


