always @( * ) begin
  if ( !vcmain_pok_i )                 en_osc_re = 1'b0;  // For Startup
  else if ( sys_en_i && vcmain_pok_i ) en_osc_re = #(SYS_EN_RDLY) 1'b1;
  else                                 en_osc_re = 1'b0;
